/* Cursor piscante */
@keyframes blink {
  0%, 100% { opacity: 1; }
  50% { opacity: 0; }
}

.typewriter-cursor {
  display: inline-block;
  width: 2px;
  height: 1.1em;
  background: currentColor;
  vertical-align: middle;
  margin-left: 2px;
  animation: blink 1s step-end infinite;
}

code.usage:
const { displayed, done } = useTypewriter(
  "Glad you stopped in. Good taste tends to find us. Now, what are we building?",
  38,   // velocidade: 38ms = natural, 20ms = rápido, 60ms = pensativo
  600,  // delay inicial: tempo para o usuário ler o heading primeiro
);

<p style={{ minHeight: '54px' }}>
  {displayed}
  {!done && <span className="typewriter-cursor" />}
</p>

